                style={{ flex: 1 }}
                onClick={() => {
                  setDraftValue([]);
                }}
              >
                Reset
              </Button>
              <Button
                size="small"
                style={{ flex: 1 }}
                onClick={() => {
                  setValue(draftValue);
                  setOpen(false);
                  args.onOpenChange?.(false);
                }}
              >
                Apply
              </Button>
            </div>
          )}
          onOpenChange={(nextOpen) => {
            setOpen(nextOpen);
            setDraftValue(value);
            args.onOpenChange?.(nextOpen);
          }}
          onChange={(nextValue, option) => {
            setDraftValue((nextValue as Array<string | number>) ?? []);
            args.onChange?.(nextValue, option);
          }}
        />
      </div>
    );
  }

